# redis-cli pipelining
user@server:~$ cat commands.txt
SET user:1:name "Alice"
SET user:1:email "alice@example.com"
INCR counter:users
user@server:~$ cat commands.txt | redis-cli --pipe

# Python (redis-py)
import redis

r = redis.Redis(host='localhost', port=6379, decode_responses=True)
pipe = r.pipeline()
pipe.set('user:1:name', 'Alice')
pipe.set('user:1:email', 'alice@example.com')
pipe.incr('counter:users')
results = pipe.execute()  # Returns [True, True, 1]

# Node.js (ioredis)
const Redis = require('ioredis');
const redis = new Redis();

const pipeline = redis.pipeline();
pipeline.set('user:1:name', 'Alice');
pipeline.set('user:1:email', 'alice@example.com');
pipeline.incr('counter:users');
const results = await pipeline.exec();

# Connection pooling is CRITICAL for production Redis performance.
# Without pooling, every request opens/closes a TCP connection — O(10ms) overhead!

# Python (redis-py — built-in pool)
import redis

# Connection pool is created automatically (one per Redis instance)
r = redis.Redis(
    host='localhost',
    port=6379,
    decode_responses=True,
    max_connections=50,  # Max pool size
    socket_connect_timeout=5,
    socket_timeout=5,
    retry_on_timeout=True,
    health_check_interval=30  # Periodic health checks
)

# Use normally — pool manages connections transparently
r.set('key', 'value')
r.get('key')

# Check pool stats
info = r.connection_pool._available_connections
print(f"Available connections: {len(info)}")

# Node.js (ioredis — built-in pool)
const Redis = require('ioredis');

const redis = new Redis({
    host: 'localhost',
    port: 6379,
    maxRetriesPerRequest: 3,
    retryStrategy: (times) => Math.min(times * 50, 2000),
    enableReadyCheck: true,
    lazyConnect: true,  // Don't connect on instantiation
    connectionName: 'my-app',  // Identify in CLIENT LIST
    keepAlive: 10000,  // TCP keepalive
    db: 0
});

await redis.connect();  // Explicit connect

